SHOR_VULNERABLE = ['RSA', 'ECDSA', 'ECDH', 'DH', 'DSA', 'ED25519', 'ED448', 'ELGAMAL', 'ECC']
GROVER_AFFECTED = ['AES', 'CHACHA20', 'SHA', '3DES', 'BLOWFISH']
QUANTUM_SAFE = ['KYBER', 'DILITHIUM', 'SPHINCS', 'FALCON', 'MCELIECE']

def categorize_algorithm(algo: str) -> dict:
    algo_upper = algo.upper()

    for safe in QUANTUM_SAFE:
        if safe in algo_upper:
            return {'category': 'quantum-safe', 'vulnerable_to': None, 'status': 'SAFE'}

    for vuln in SHOR_VULNERABLE:
        if vuln in algo_upper:
            return {'category': 'asymmetric', 'vulnerable_to': 'Shor', 'status': 'BROKEN'}

    for affected in GROVER_AFFECTED:
        if affected in algo_upper:
            # Check key size
            bits = 128  # default
            for num in ['256', '192', '128', '512', '384']:
                if num in algo:
                    bits = int(num)
                    break

            quantum_security = bits // 2
            if quantum_security >= 128:
                return {'category': 'symmetric', 'vulnerable_to': 'Grover', 'status': 'ADEQUATE'}
            else:
                return {'category': 'symmetric', 'vulnerable_to': 'Grover', 'status': 'WEAK'}

    return {'category': 'unknown', 'vulnerable_to': 'unknown', 'status': 'REVIEW'}

def scan_crypto_config(config: dict) -> dict:
    vulnerabilities = []
    risk_level = 'LOW'
    recommendations = []

    for component, algorithms in config.items():
        if isinstance(algorithms, str):
            algorithms = [algorithms]

        for algo in algorithms:
            result = categorize_algorithm(algo)

            if result['status'] == 'BROKEN':
                vulnerabilities.append({
                    'component': component,
                    'algorithm': algo,
                    'issue': f"Broken by {result['vulnerable_to']}'s algorithm",
                    'severity': 'CRITICAL'
                })
                risk_level = 'CRITICAL'
                recommendations.append(f"Replace {algo} in {component} with PQC alternative")

            elif result['status'] == 'WEAK':
                vulnerabilities.append({
                    'component': component,
                    'algorithm': algo,
                    'issue': 'Insufficient quantum security',
                    'severity': 'HIGH'
                })
                if risk_level != 'CRITICAL':
                    risk_level = 'HIGH'
                recommendations.append(f"Upgrade {algo} to 256-bit variant")

    return {
        'vulnerabilities': vulnerabilities,
        'risk_level': risk_level,
        'recommendations': recommendations,
        'total_issues': len(vulnerabilities)
    }

def generate_report(scan_results: list) -> str:
    report = "QUANTUM VULNERABILITY REPORT\n" + "=" * 40 + "\n\n"

    for result in scan_results:
        report += f"Risk Level: {result['risk_level']}\n"
        report += f"Total Issues: {result['total_issues']}\n\n"

        for vuln in result['vulnerabilities']:
            report += f"[{vuln['severity']}] {vuln['component']}: {vuln['algorithm']}\n"
            report += f"  Issue: {vuln['issue']}\n\n"

        report += "Recommendations:\n"
        for rec in result['recommendations']:
            report += f"  • {rec}\n"

    return report

def calculate_priority_score(system: dict) -> dict:
    score = 0
    breakdown = {}

    # Crypto vulnerability (0-40 points)
    crypto_score = 0
    for algo in system.get('crypto_algorithms', []):
        algo_upper = algo.upper()
        if any(v in algo_upper for v in ['RSA', 'ECDSA', 'ECDH', 'DH', 'DSA', 'ECC']):
            crypto_score = max(crypto_score, 40)
        elif 'AES-128' in algo_upper or 'AES128' in algo_upper:
            crypto_score = max(crypto_score, 20)
    score += crypto_score
    breakdown['crypto_vulnerability'] = crypto_score

    # Data sensitivity (0-25 points)
    sensitivity_scores = {'low': 5, 'medium': 10, 'high': 20, 'critical': 25}
    sens_score = sensitivity_scores.get(system.get('data_sensitivity', 'medium'), 10)
    score += sens_score
    breakdown['data_sensitivity'] = sens_score

    # Retention period (0-20 points)
    retention = system.get('retention_years', 5)
    if retention > 25:
        ret_score = 20
    elif retention > 15:
        ret_score = 15
    elif retention > 10:
        ret_score = 10
    else:
        ret_score = 5
    score += ret_score
    breakdown['retention_period'] = ret_score

    # Update difficulty (0-15 points) - harder = higher priority (start early)
    difficulty_scores = {'easy': 0, 'medium': 5, 'hard': 10, 'very_hard': 15}
    diff_score = difficulty_scores.get(system.get('update_difficulty', 'medium'), 5)
    score += diff_score
    breakdown['update_difficulty'] = diff_score

    # Determine priority level
    if score >= 70:
        priority = 'CRITICAL'
    elif score >= 50:
        priority = 'HIGH'
    elif score >= 30:
        priority = 'MEDIUM'
    else:
        priority = 'LOW'

    return {
        'system_name': system.get('name', 'Unknown'),
        'score': score,
        'priority_level': priority,
        'breakdown': breakdown
    }

def prioritize_systems(systems: list) -> list:
    scored = [calculate_priority_score(s) for s in systems]
    return sorted(scored, key=lambda x: x['score'], reverse=True)

def generate_migration_timeline(prioritized_systems: list) -> dict:
    timeline = {
        'immediate': [],     # CRITICAL - start now
        'short_term': [],    # HIGH - 1-2 years
        'medium_term': [],   # MEDIUM - 2-5 years
        'long_term': []      # LOW - 5+ years
    }

    for system in prioritized_systems:
        if system['priority_level'] == 'CRITICAL':
            timeline['immediate'].append(system['system_name'])
        elif system['priority_level'] == 'HIGH':
            timeline['short_term'].append(system['system_name'])
        elif system['priority_level'] == 'MEDIUM':
            timeline['medium_term'].append(system['system_name'])
        else:
            timeline['long_term'].append(system['system_name'])

    return timeline

PROTOCOL_SPECS = {
    'TLS': {
        'key_exchange': ['ECDHE', 'DHE', 'RSA'],
        'authentication': ['RSA', 'ECDSA'],
        'encryption': ['AES-128-GCM', 'AES-256-GCM', 'ChaCha20-Poly1305'],
        'dependencies': ['PKI', 'DNS'],
        'cascades_to': ['HTTPS', 'SMTPS', 'IMAPS', 'API']
    },
    'SSH': {
        'key_exchange': ['ECDH', 'DH'],
        'host_auth': ['RSA', 'ECDSA', 'ED25519'],
        'user_auth': ['RSA', 'ECDSA', 'ED25519'],
        'encryption': ['AES-256-CTR', 'ChaCha20-Poly1305'],
        'dependencies': [],
        'cascades_to': ['Git', 'SFTP', 'SCP', 'Remote Admin']
    },
    'IPsec': {
        'key_exchange': ['IKEv2 (DH/ECDH)'],
        'authentication': ['RSA', 'ECDSA', 'PSK'],
        'encryption': ['AES-GCM', 'ChaCha20'],
        'dependencies': ['PKI'],
        'cascades_to': ['VPN', 'Site-to-Site']
    },
    'PKI': {
        'signatures': ['RSA', 'ECDSA'],
        'key_encapsulation': ['RSA'],
        'dependencies': [],
        'cascades_to': ['TLS', 'Code Signing', 'Email', 'Document Signing']
    }
}

def map_protocol_dependencies(protocol: str) -> dict:
    spec = PROTOCOL_SPECS.get(protocol.upper(), {})
    if not spec:
        return {'error': f'Unknown protocol: {protocol}'}

    vulnerabilities = []
    for component, algos in spec.items():
        if component in ['dependencies', 'cascades_to']:
            continue
        for algo in algos:
            if any(v in algo.upper() for v in ['RSA', 'ECDSA', 'ECDH', 'DH', 'ED25519']):
                vulnerabilities.append({
                    'component': component,
                    'algorithm': algo,
                    'threat': 'Shor'
                })

    return {
        'protocol': protocol,
        'components': spec,
        'vulnerabilities': vulnerabilities,
        'cascades_to': spec.get('cascades_to', [])
    }

def analyze_cascade_effect(compromised_algo: str, protocols: list) -> dict:
    affected = []
    functions = []

    for proto in protocols:
        mapping = map_protocol_dependencies(proto)
        for vuln in mapping.get('vulnerabilities', []):
            if compromised_algo.upper() in vuln['algorithm'].upper():
                affected.append(proto)
                functions.append(f"{proto}: {vuln['component']}")
                affected.extend(mapping.get('cascades_to', []))

    affected = list(set(affected))

    return {
        'compromised': compromised_algo,
        'affected_protocols': affected,
        'affected_functions': functions,
        'impact': f"Compromising {compromised_algo} affects {len(affected)} protocols/systems"
    }

def create_dependency_graph(protocols: list) -> dict:
    graph = {'nodes': [], 'edges': []}

    for proto in protocols:
        mapping = map_protocol_dependencies(proto)
        graph['nodes'].append({'id': proto, 'type': 'protocol', 'vulnerable': len(mapping.get('vulnerabilities', [])) > 0})

        for cascade in mapping.get('cascades_to', []):
            graph['edges'].append({'from': proto, 'to': cascade, 'type': 'cascades_to'})

    return graph
